package com.veetu.vadagai.auth;import com.veetu.vadagai.user.User;import io.jsonwebtoken.*;import io.jsonwebtoken.security.Keys;import org.springframework.beans.factory.annotation.Value;import org.springframework.stereotype.Service;import javax.crypto.SecretKey;import java.nio.charset.StandardCharsets;import java.time.*;import java.util.*;
@Service public class JwtService{private final SecretKey key;private final long minutes;public JwtService(@Value("${security.jwt.secret}") String secret,@Value("${security.jwt.access-token-minutes}") long minutes){this.key=Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8));this.minutes=minutes;}public String create(User u){Instant now=Instant.now();return Jwts.builder().subject(u.getEmail()).claim("roles",u.getRoles().stream().map(Enum::name).toList()).issuedAt(Date.from(now)).expiration(Date.from(now.plus(Duration.ofMinutes(minutes)))).signWith(key).compact();}public String subject(String token){return Jwts.parser().verifyWith(key).build().parseSignedClaims(token).getPayload().getSubject();}}
